    open: MULTIPLE_OPEN_STRATEGY.open,
    select: ({id, value, opened, parents}) => {
        if (!value) return opened

        const path: Array<unknown> = []

        let parent = parents.get(id)

        while (parent != null) {
            path.push(parent)
            parent = parents.get(parent)
        }

        return new Set(path)
    }
}

