export const MULTIPLE_OPEN_STRATEGY: TStrategyOpen = {
    open: ({id, value, opened, parents}) => {
        if (value) {
            let parent = parents.get(id)
            opened.add(id)

            while (parent != null && parent !== id) {
                opened.add(parent)
                parent = parents.get(parent)
            }

            return opened
        } else {
            opened.delete(id)
        }

        return opened
    },
    select: () => null
}

